// .eslintrc.json for a TypeScript MCP server or LangChain.js agent
{
  "extends": ["eslint:recommended", "plugin:@typescript-eslint/recommended"],
  "plugins": ["@typescript-eslint"],
  "rules": {
    "no-unused-vars": "error",
    "@typescript-eslint/no-explicit-any": "warn",
    "@typescript-eslint/explicit-function-return-type": "error"
  }
}

// .prettierrc for consistent JS/TS formatting
{
  "semi": true,
  "singleQuote": false,
  "trailingComma": "es5",
  "printWidth": 100,
  "tabWidth": 2
}

# Example: what the S rule group catches
import subprocess

# S603 + S604: shell injection risk
def run_agent_command(user_input: str) -> str:
    result = subprocess.run(user_input, shell=True, capture_output=True)  # S603, S604
    return result.stdout.decode()

# Safe version: explicit args list, no shell=True
def run_agent_command_safe(command: list[str]) -> str:
    result = subprocess.run(command, capture_output=True, check=True)  # noqa: S603 (shell=False is the default)
    return result.stdout.decode()
